mapper.select:
select m.id, m.meeting_type, m.title, m.scheduled_at, m.duration_minutes, m.host_id, u.real_name as host_name, m.location, m.status, m.created_at, m.updated_at from meeting_plan m left join sys_user u on u.id = m.host_id where m.project_id = #{projectId}
and m.meeting_type = #{query.meetingType}
and m.status = #{query.status}
and m.host_id = #{query.hostId}
order by m.scheduled_at desc, m.updated_at desc

