    id, project_id, meeting_type, title, scheduled_at, duration_minutes, host_id, location, status, created_at, updated_at
) values (
    #{id}, #{projectId}, #{meetingType}, #{title}, #{scheduledAt}, #{durationMinutes}, #{hostId}, #{location}, #{status}, #{createdAt}, #{updatedAt}
)

