mapper.select:
select count(1)
from communication_record
where project_id = #{projectId}
  and meeting_id = #{meetingId}
  and is_deleted = 0

select cr.id, cr.meeting_id, m.title as meeting_title, cr.record_type, cr.title, cr.content, cr.recorder_id, u.real_name as recorder_name, cr.created_at, cr.updated_at from communication_record cr left join meeting_plan m on m.id = cr.meeting_id left join sys_user u on u.id = cr.recorder_id where cr.project_id = #{projectId} and cr.is_deleted = 0
and cr.record_type = #{query.recordType}
and cr.meeting_id = #{query.meetingId}
and cr.recorder_id = #{query.recorderId}
order by cr.updated_at desc, cr.created_at desc

