)

mapper.update:
update communication_record
set meeting_id = #{meetingId},
    record_type = #{recordType},
    title = #{title},
    content = #{content},
    recorder_id = #{recorderId},
    updated_at = #{updatedAt}
where project_id = #{projectId}
  and id = #{id}
  and is_deleted = 0

update communication_record
set is_deleted = 1,
    updated_at = #{updatedAt}
where project_id = #{projectId}
  and id = #{id}
